CREATE TABLE reagent_lot(id BIGINT PRIMARY KEY AUTO_INCREMENT,lot_no VARCHAR(64) NOT NULL,reagent_code VARCHAR(64) NOT NULL,manufacturer VARCHAR(128),manufacture_date DATE,expires_date DATE,status VARCHAR(32) NOT NULL,UNIQUE KEY uk_reagent_lot(lot_no,reagent_code));
CREATE TABLE cartridge(id BIGINT PRIMARY KEY AUTO_INCREMENT,cartridge_no VARCHAR(64) NOT NULL,cartridge_type VARCHAR(64) NOT NULL,reagent_lot_id BIGINT NOT NULL,expires_at DATETIME(3),status VARCHAR(32) NOT NULL,UNIQUE KEY uk_cartridge_no(cartridge_no));
CREATE TABLE sample(id BIGINT PRIMARY KEY AUTO_INCREMENT,sample_no VARCHAR(64) NOT NULL,organization_id VARCHAR(64) NOT NULL,external_no VARCHAR(128),specimen_type VARCHAR(64) NOT NULL,status VARCHAR(32) NOT NULL,collected_at DATETIME(3),created_at DATETIME(3) NOT NULL,UNIQUE KEY uk_sample_no(sample_no),KEY idx_sample_org_external(organization_id,external_no));
CREATE TABLE detection_order(id BIGINT PRIMARY KEY AUTO_INCREMENT,order_no VARCHAR(64) NOT NULL,sample_id BIGINT NOT NULL,assay_code VARCHAR(64) NOT NULL,status VARCHAR(32) NOT NULL,created_at DATETIME(3) NOT NULL,UNIQUE KEY uk_order_no(order_no),KEY idx_order_sample(sample_id));
CREATE TABLE instrument_run(id BIGINT PRIMARY KEY AUTO_INCREMENT,run_no VARCHAR(64) NOT NULL,order_id BIGINT NOT NULL,cartridge_id BIGINT NOT NULL,instrument_no VARCHAR(64) NOT NULL,status VARCHAR(32) NOT NULL,started_at DATETIME(3),ended_at DATETIME(3),UNIQUE KEY uk_run_no(run_no),KEY idx_run_order(order_id));
